const now = new Date();
const dayOfWeek = now.getDay();
const mondayOffset = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
const monday = new Date(now);
monday.setDate(now.getDate() + mondayOffset);
monday.setHours(0, 0, 0, 0);
const nextFriday = new Date(monday);
nextFriday.setDate(monday.getDate() + 11);
nextFriday.setHours(23, 59, 59, 999);

const todayStr = now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const workStart = $.input.workHoursStart || 9;
const workEnd = $.input.workHoursEnd || 17;

return { timeMin: monday.toISOString(), timeMax: nextFriday.toISOString(), today: todayStr, workStart, workEnd };

const response = $.steps.listEvents.response;
const events = response.items || response.data || [];
let compiled = '';
let eventCount = 0;

if (Array.isArray(events)) {
  events.forEach((e, i) => {
    const startTime = e.start ? (e.start.dateTime || e.start.date || '') : '';
    const endTime = e.end ? (e.end.dateTime || e.end.date || '') : '';
    compiled += 'EVENT ' + (i + 1) + ': ' + (e.summary || '(no title)') + '\n';
    compiled += '  Start: ' + startTime + ' | End: ' + endTime + '\n';
    if (e.location) compiled += '  Location: ' + e.location + '\n';
    const attendees = (e.attendees || []).map(a => (a.displayName || a.email)).join(', ');
    if (attendees) compiled += '  Attendees: ' + attendees + '\n';
    if (e.description) compiled += '  Notes: ' + (e.description || '').slice(0, 150) + '\n';
    compiled += '\n';
    eventCount++;
  });
}

return { compiled, eventCount };

const d = $.steps.compileSchedule.output;
const dr = $.steps.getDateRange.output;
const request = $.input.schedulingRequest || '';

let prompt = 'You are an expert calendar and scheduling assistant. Analyze the following calendar and provide comprehensive scheduling advice.\n\n';
prompt += 'CURRENT DATE: ' + dr.today + '\n';
prompt += 'WORK HOURS: ' + dr.workStart + ':00 to ' + dr.workEnd + ':00\n';
prompt += 'TOTAL EVENTS: ' + d.eventCount + '\n\n';

if (request) {
  prompt += 'SCHEDULING REQUEST: ' + request + '\n\n';
}

prompt += 'CALENDAR EVENTS:\n' + d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Find available time slots for meetings (minimum 30 min blocks)\n';
prompt += '- Suggest meetings that could be rescheduled to optimize the week\n';
prompt += '- Identify back-to-back meetings needing buffer time\n';
prompt += '- Suggest meeting prep tasks for important meetings\n';
prompt += '- Recommend times for deep focus work\n';
prompt += '- If a scheduling request was given, provide specific slot recommendations\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "availableSlots": [{ "day": "Monday", "date": "YYYY-MM-DD", "time": "10:00-11:00", "duration": "1 hour", "quality": "ideal|good|okay" }],\n';
prompt += '  "rescheduleSuggestions": [{ "event": "meeting name", "currentTime": "when", "suggestedTime": "when", "reason": "why" }],\n';
prompt += '  "bufferNeeded": [{ "between": ["meeting1", "meeting2"], "suggestion": "add 15 min buffer" }],\n';
prompt += '  "meetingPrep": [{ "meeting": "name", "when": "day/time", "prepTasks": ["task 1", "task 2"], "prepTime": "30 min" }],\n';
prompt += '  "focusTimeBlocks": [{ "day": "day", "time": "start-end", "bestFor": "type of work" }],\n';
prompt += '  "schedulingResponse": "response to the specific scheduling request if any",\n';
prompt += '  "weekSummary": "overview of the week ahead",\n';
prompt += '  "topRecommendation": "single most important scheduling advice"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { availableSlots: [], rescheduleSuggestions: [], bufferNeeded: [], meetingPrep: [], focusTimeBlocks: [], schedulingResponse: '', weekSummary: raw, topRecommendation: '' }; }

const ai = $.steps.parseAI.output;
const dr = $.steps.getDateRange.output;
const request = $.input.schedulingRequest || '';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'AI Calendar Scheduling Assistant', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Date:* ' + dr.today + ' | *Work hours:* ' + dr.workStart + ':00 - ' + dr.workEnd + ':00' } });

if (ai.topRecommendation) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':bulb: *Top Recommendation:* ' + ai.topRecommendation } });
}
blocks.push({ type: 'divider' });

const summary = (ai.weekSummary || 'No analysis available.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Week Overview:*\n' + summary } });

if (request && ai.schedulingResponse) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Your Request:* ' + request + '\n\n*Response:* ' + ai.schedulingResponse } });
}

if (ai.availableSlots && ai.availableSlots.length > 0) {
  blocks.push({ type: 'divider' });
  let slotText = '*Available Time Slots:*\n';
  ai.availableSlots.slice(0, 8).forEach(s => {
    const qualityIcon = s.quality === 'ideal' ? ':star:' : s.quality === 'good' ? ':white_check_mark:' : ':ok:';
    slotText += qualityIcon + ' ' + s.day + ' ' + s.time + ' (' + s.duration + ')\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: slotText.slice(0, 1800) } });
}

if (ai.rescheduleSuggestions && ai.rescheduleSuggestions.length > 0) {
  blocks.push({ type: 'divider' });
  let reText = '*Reschedule Suggestions:*\n';
  ai.rescheduleSuggestions.slice(0, 5).forEach((r, i) => {
    reText += (i + 1) + '. *' + r.event + '*: Move from ' + r.currentTime + ' to ' + r.suggestedTime + '\n';
    reText += '   _Reason: ' + r.reason + '_\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: reText.slice(0, 1800) } });
}

if (ai.meetingPrep && ai.meetingPrep.length > 0) {
  blocks.push({ type: 'divider' });
  let prepText = '*Meeting Prep:*\n';
  ai.meetingPrep.slice(0, 5).forEach((m, i) => {
    prepText += (i + 1) + '. *' + m.meeting + '* (' + m.when + ') - ' + m.prepTime + ' needed\n';
    (m.prepTasks || []).forEach(t => { prepText += '   - ' + t + '\n'; });
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: prepText.slice(0, 1800) } });
}

if (ai.focusTimeBlocks && ai.focusTimeBlocks.length > 0) {
  blocks.push({ type: 'divider' });
  let focusText = '*Focus Time Blocks:*\n';
  ai.focusTimeBlocks.slice(0, 5).forEach((f, i) => {
    focusText += (i + 1) + '. ' + f.day + ' ' + f.time + ' - Best for: ' + f.bestFor + '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: focusText.slice(0, 1800) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Google Calendar + Claude AI | One CLI' }] });

const fallbackText = 'Calendar Assistant: ' + (ai.availableSlots || []).length + ' slots found - ' + (ai.topRecommendation || ai.weekSummary || '').slice(0, 100);
return { blocks, fallbackText };
